template <int WIN_SIZE_X, int WIN_SIZE_Y>
class RDWT53 {
private: 
    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> RDWT53Buffer;
    RDWT53Buffer buffer;
    enum { STRIDE = RDWT53Buffer::VERTICAL_STRIDE };
    template <bool CHECKED>
    struct RDWT53Column {
      VerticalDWTBandLoader<int, CHECKED> loader;
      int offset;
      void clear() {
        offset = 0;
        loader.clear();
      }
    };

    void horizontalTransform(const int lines, const int firstLine, int threadIdx_x) {
      buffer.forEachHorizontalEven(firstLine, lines, Reverse53Update(), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, Reverse53Predict(), threadIdx_x);
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const int * const input, RDWT53Column<CHECKED> & col) {
      for(int i = 3; i < (3 + WIN_SIZE_Y); i += 2) {
        buffer[col.offset + i * STRIDE] = col.loader.loadLowFrom(input);
        buffer[col.offset + (i + 1) * STRIDE] = col.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED>
    void initColumn(const int columnX, const int * const input, const int sizeX, const int sizeY,
                    RDWT53Column<CHECKED> & column, const int firstY, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      const int firstX = blockIdx_x * WIN_SIZE_X + columnX;
      column.offset = buffer.getColumnOffset(columnX);
      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 0 * STRIDE] = buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 1);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
      }
    }

    template<bool CHECKED_LOADS, bool CHECKED_WRITES>
    void transform(const int * const in, int * const out, const int sizeX, const int sizeY,
                   const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT53Column<CHECKED_LOADS> column, boundaryColumn;
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      boundaryColumn.clear();
      if(threadIdx_x < 3) {
        const int colId = threadIdx_x + ((threadIdx_x != 2) ? WIN_SIZE_X : -3);
        initColumn(colId, in, sizeX, sizeY, boundaryColumn, firstY, blockIdx_x, blockIdx_y, threadIdx_x);
      }
      initColumn(parityIdx(WIN_SIZE_X, threadIdx_x), in, sizeX, sizeY, column, firstY, blockIdx_x, blockIdx_y, threadIdx_x);
      horizontalTransform(3, 0, threadIdx_x);
      const int outX = blockIdx_x * WIN_SIZE_X + threadIdx_x;
      VerticalDWTPixelWriter<int, CHECKED_WRITES> writer;
      writer.init(sizeX, sizeY, outX, firstY);
      const int outputColumnOffset = buffer.getColumnOffset(threadIdx_x);
      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(in, column);
        if(threadIdx_x < 3) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalTransform(WIN_SIZE_Y, 3, threadIdx_x);
        int last3Lines[3];
        last3Lines[0] = buffer[outputColumnOffset + (WIN_SIZE_Y + 0) * STRIDE];
        last3Lines[1] = buffer[outputColumnOffset + (WIN_SIZE_Y + 1) * STRIDE];
        last3Lines[2] = buffer[outputColumnOffset + (WIN_SIZE_Y + 2) * STRIDE];
        buffer.forEachVerticalOdd(outputColumnOffset, Reverse53Update(), threadIdx_x);
        buffer.forEachVerticalEven(outputColumnOffset, Reverse53Predict(), threadIdx_x);
        for(int i = 1; i < (1 + WIN_SIZE_Y); i++) {
          writer.writeInto(out, buffer[outputColumnOffset + i * STRIDE]);
        }
        buffer[outputColumnOffset + 0 * STRIDE] = last3Lines[0];
        buffer[outputColumnOffset + 1 * STRIDE] = last3Lines[1];
        buffer[outputColumnOffset + 2 * STRIDE] = last3Lines[2];
      }
    }
public:
    static void run(const int * const input, int * const output, const int sx, const int sy, const int steps,
                    int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT53<WIN_SIZE_X, WIN_SIZE_Y> rdwt53;
      const int maxX = (blockIdx_x + 1) * WIN_SIZE_X + 1;
      const int maxY = (blockIdx_y + 1) * WIN_SIZE_Y * steps + 1;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        rdwt53.transform<true, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else if(atRightBoudary) {
        rdwt53.transform<false, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else {
        rdwt53.transform<false, false>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      }
    }
};

__kernel void cl_rdwt53Kernel(const int * const in, int * const out,
                               const int sx, const int sy, const int steps,
                               const int WIN_SX, const int WIN_SY) {
    RDWT53<WIN_SX, WIN_SY>::run(in, out, sx, sy, steps,
                                get_group_id(0), get_group_id(1), get_local_id(0));
}

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class RDWT97Class {
private:
    template <bool CHECKED>
    struct RDWT97Column  {
      VerticalDWTBandLoader<float, CHECKED> loader;
      int offset;
      void clear() {
        loader.clear();
        offset = 0;
      }
    };
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> RDWT97Buffer;
    RDWT97Buffer buffer;
    enum { STRIDE = RDWT97Buffer::VERTICAL_STRIDE };

    void horizontalRDWT97(int lines, int firstLine, int threadIdx_x) {
      buffer.scaleHorizontal(scale97Mul, scale97Div, firstLine, lines, threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(r97update2), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(r97predict2), threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(r97update1), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(r97Predict1), threadIdx_x);
    }

    template <bool CHECKED>
    void initColumn(const int colIndex, const float * const input, const int sizeX, const int sizeY,
                    RDWT97Column<CHECKED> & column, const int firstY, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      const int firstX = blockIdx_x * WIN_SIZE_X + colIndex;
      column.offset = buffer.getColumnOffset(colIndex);
      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 3 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 4 * STRIDE] = buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 5 * STRIDE] = buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 6 * STRIDE] = buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 3);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 3 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 5 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 6 * STRIDE] = column.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(RDWT97Column<CHECKED> & col, const float * const input) {
      for(int i = 7; i < (7 + WIN_SIZE_Y); i += 2) {
        buffer[col.offset + i * STRIDE] = col.loader.loadLowFrom(input);
        buffer[col.offset + (i + 1) * STRIDE] = col.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED_LOADS, bool CHECKED_WRITES>
    void transform(const float * const in, float * const out, const int sizeX, const int sizeY,
                   const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT97Column<CHECKED_LOADS> column;
      RDWT97Column<CHECKED_LOADS> boundaryColumn;
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      boundaryColumn.clear();
      if(threadIdx_x < 7) {
        const int colId = threadIdx_x + ((threadIdx_x < 4) ? WIN_SIZE_X : -7);
        initColumn(colId, in, sizeX, sizeY, boundaryColumn, firstY, blockIdx_x, blockIdx_y, threadIdx_x);
      }
      initColumn(parityIdx(WIN_SIZE_X, threadIdx_x), in, sizeX, sizeY, column, firstY, blockIdx_x, blockIdx_y, threadIdx_x);
      horizontalRDWT97(7, 0, threadIdx_x);
      const int outputX = blockIdx_x * WIN_SIZE_X + threadIdx_x;
      VerticalDWTPixelWriter<float, CHECKED_WRITES> writer;
      writer.init(sizeX, sizeY, outputX, firstY);
      const int outColumnOffset = buffer.getColumnOffset(threadIdx_x);
      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(column, in);
        if(threadIdx_x < 7) {
          loadWindowIntoColumn(boundaryColumn, in);
        }
        horizontalRDWT97(WIN_SIZE_Y, 7, threadIdx_x);
        float last7Lines[7];
        for(int i = 0; 7 > i; i++) {
          last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
        }
        buffer.scaleVertical(scale97Div, scale97Mul, outColumnOffset, WIN_SIZE_Y + 7, 0);
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(r97update2), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(r97predict2), threadIdx_x);
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(r97update1), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(r97Predict1), threadIdx_x);
        for(int i = 3; i < (3 + WIN_SIZE_Y); i++) {
          writer.writeInto(out, buffer[outColumnOffset + i * STRIDE]);
        }
        for(int i = 0; i < 7; i++) {
          buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
        }
      }
    }
public:
    static void run(const float * const input, float * const output, const int sx, const int sy, const int steps,
                    int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT97Class<WIN_SIZE_X, WIN_SIZE_Y> rdwt97;
      const int maxX = (blockIdx_x + 1) * WIN_SIZE_X + 3;
      const int maxY = (blockIdx_y + 1) * WIN_SIZE_Y * steps + 3;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        rdwt97.transform<true, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else if(atRightBoudary) {
        rdwt97.transform<false, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else {
        rdwt97.transform<false, false>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      }
    }
};

