#define THREADS 256

void storeComponents_float(float *d_r, float *d_g, float *d_b, float r, float g, float b, int pos)
{
    d_r[pos] = (r/255.0f) - 0.5f;
    d_g[pos] = (g/255.0f) - 0.5f;
    d_b[pos] = (b/255.0f) - 0.5f;
}

void storeComponents_int(int *d_r, int *d_g, int *d_b, int r, int g, int b, int pos)
{
    d_r[pos] = r - 128;
    d_g[pos] = g - 128;
    d_b[pos] = b - 128;
} 

void storeComponent_float(float *d_c, float c, int pos)
{
    d_c[pos] = (c/255.0f) - 0.5f;
}

void storeComponent_int(int *d_c, int c, int pos)
{
    d_c[pos] = c - 128;
}

__kernel void c_CopySrcToComponents_float(float *d_r, float *d_g, float *d_b, 
                                  unsigned char * d_src, 
                                  int pixels)
{
    int x  = get_local_id(0);
    int gX = get_local_size(0) * get_group_id(0);

    unsigned char sData[THREADS*3];

    if ( (x*4) < THREADS*3 ) {
        float *s = (float *)d_src;
        float *d = (float *)sData;
        d[x] = s[((gX*3)>>2) + x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float r, g, b;

    int offset = x*3;
    r = (float)(sData[offset]);
    g = (float)(sData[offset+1]);
    b = (float)(sData[offset+2]);

    int globalOutputPosition = gX + x;
    if (globalOutputPosition < pixels) {
        storeComponents_float(d_r, d_g, d_b, r, g, b, globalOutputPosition);
    }
}

