#define IMUL(a, b) ((a)*(b))
#define DIVANDRND(a, b) ((((a) % (b)) != 0) ? ((a) / (b) + 1) : ((a) / (b)))

const float f97Predict1 = -1.586134342f;   
const float f97Update1 = -0.05298011854f;  
const float f97Predict2 = 0.8829110762f;   
const float f97Update2 = 0.4435068522f;    

const float r97update2 = -f97Update2;    
const float r97predict2 = -f97Predict2;  
const float r97update1 = -f97Update1;    
const float r97Predict1 = -f97Predict1;  

const float scale97Mul = 1.23017410491400f;
const float scale97Div = 1.0f / scale97Mul;

const float forward53Predict = -0.5f;   
const float forward53Update = 0.25f;    

const float reverse53Update = -forward53Update;    
const float reverse53Predict = -forward53Predict;  

int parityIdx_int(int THREADS) {
    int x = get_local_id(0);
    return (x * 2) - (THREADS - 1) * (x / (THREADS / 2));
}

int divRndUp_int(int n, int d) {
    return (n / d) + ((n % d) ? 1 : 0);
}

void mirror_int(int * d, const int sizeD) {
    if(*d >= sizeD) {
        *d = 2 * sizeD - 2 - *d;
    } else if(*d < 0) {
        *d = -(*d);
    }
}

int initialize_pixel_int(int sizeX, int sizeY, int firstX, int firstY, int strideX) {
    return firstX + sizeX * firstY;
}

__kernel void cl_fdwt53Kernel(const int * input, int * output,
                               const int sizeX, const int sizeY,
                               const int winSteps, const int WIN_SX, const int WIN_SY) {
    const int STRIDE = (WIN_SX / 2) + 2;
    const int BUFFER_SIZE = STRIDE * (WIN_SY + 3);
    const int SHM_BANKS = 16;
    const int PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS);
    const int ODD_OFFSET = BUFFER_SIZE + PADDING;

    int data[2 * BUFFER_SIZE + PADDING];

    int x = get_local_id(0);
    int gx = get_group_id(0);
    int gy = get_group_id(1);

    int column_offset = (x + 2) / 2 + ((x + 2) & 1) * ODD_OFFSET;
    int boundary_column_offset = 0;

    int col_pixel0 = 0, col_pixel1 = 0, col_pixel2 = 0;
    int col_loader_last = 0, col_loader_stride = 0, col_loader_end = 0;

    int bound_pixel0 = 0, bound_pixel1 = 0, bound_pixel2 = 0;
    int bound_loader_last = 0, bound_loader_stride = 0, bound_loader_end = 0;

    const int firstY = gy * WIN_SY * winSteps;
    const int firstX = gx * WIN_SX + x;
    int mirror_x = firstX;
    if(mirror_x >= sizeX) mirror_x = 2 * sizeX - 2 - mirror_x;
    else if(mirror_x < 0) mirror_x = -mirror_x;

    if(gy == 0) {
        col_loader_stride = sizeX;
        col_loader_end = (sizeY * sizeX + mirror_x);
        col_loader_last = initialize_pixel_int(sizeX, sizeY, mirror_x, firstY, sizeX) - sizeX;

        col_loader_last += col_loader_stride;
        if(col_loader_last == col_loader_end) { col_loader_last -= 2 * col_loader_stride; col_loader_stride = -col_loader_stride; }
        col_pixel2 = input[col_loader_last];

        col_loader_last += col_loader_stride;
        if(col_loader_last == col_loader_end) { col_loader_last -= 2 * col_loader_stride; col_loader_stride = -col_loader_stride; }
        col_pixel1 = input[col_loader_last];

        col_loader_last += col_loader_stride;
        if(col_loader_last == col_loader_end) { col_loader_last -= 2 * col_loader_stride; col_loader_stride = -col_loader_stride; }
        col_pixel0 = input[col_loader_last];

        col_loader_last = initialize_pixel_int(sizeX, sizeY, mirror_x, firstY + 1, sizeX) - sizeX;
    } else {
        col_loader_stride = sizeX;
        col_loader_end = (sizeY * sizeX + mirror_x);
        col_loader_last = initialize_pixel_int(sizeX, sizeY, mirror_x, firstY - 2, sizeX) - sizeX;

        col_loader_last += col_loader_stride;
        if(col_loader_last == col_loader_end) { col_loader_last -= 2 * col_loader_stride; col_loader_stride = -col_loader_stride; }
        col_pixel0 = input[col_loader_last];

        col_loader_last += col_loader_stride;
        if(col_loader_last == col_loader_end) { col_loader_last -= 2 * col_loader_stride; col_loader_stride = -col_loader_stride; }
        col_pixel1 = input[col_loader_last];

        col_loader_last += col_loader_stride;
        if(col_loader_last == col_loader_end) { col_loader_last -= 2 * col_loader_stride; col_loader_stride = -col_loader_stride; }
        col_pixel2 = input[col_loader_last];
    }

    if(x < 3) {
        int bound_colId = x + ((x == 0) ? WIN_SX : -3);
