template <typename T, int SIZE_X, int SIZE_Y, int BOUNDARY_X>
class TransformBuffer {
public:
    enum {
        VERTICAL_STRIDE = BOUNDARY_X + (SIZE_X / 2)
    };

private:
    enum {
        SHM_BANKS = 16,
        BUFFER_SIZE = VERTICAL_STRIDE * SIZE_Y,
        PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS),
        ODD_OFFSET = BUFFER_SIZE + PADDING,
    };

    T data[2 * BUFFER_SIZE + PADDING];

    template <typename FUNC>
    void horizontalStep(int count, int prevOffset, int midOffset, int nextOffset, const FUNC &function) {
        int STEPS = count / SIZE_X;
        int finalCount = count % SIZE_X;
        int finalOffset = count - finalCount;

        for(int i = 0; i < STEPS; i++) {
            T previous = data[prevOffset + i * SIZE_X + threadIdx.x];
            T next     = data[nextOffset + i * SIZE_X + threadIdx.x];
            T &center  = data[midOffset  + i * SIZE_X + threadIdx.x];
            function(previous, center, next);
        }

        if(threadIdx.x < finalCount) {
            T previous = data[prevOffset + finalOffset + threadIdx.x];
            T next     = data[nextOffset + finalOffset + threadIdx.x];
            T &center = data[midOffset + finalOffset + threadIdx.x];
            function(previous, center, next);
        }
    }

public:
    int getColumnOffset(int columnIndex) {
        columnIndex += BOUNDARY_X;
        return columnIndex / 2 + (columnIndex & 1) * ODD_OFFSET;
    }

    T & operator[](int index) {
        return data[index];
    }

    template <typename FUNC>
    void forEachHorizontalEven(int firstLine, int numLines, const FUNC &func) {
        int count = numLines * VERTICAL_STRIDE - 1;
        int centerOffset = firstLine * VERTICAL_STRIDE + 1;
        int prevOffset = firstLine * VERTICAL_STRIDE + ODD_OFFSET;
        int nextOffset = prevOffset + 1;
        horizontalStep(count, prevOffset, centerOffset, nextOffset, func);
    }

    template <typename FUNC>
    void forEachHorizontalOdd(int firstLine, int numLines, const FUNC &func) {
        int count = numLines * VERTICAL_STRIDE - 1;
        int prevOffset = firstLine * VERTICAL_STRIDE;
        int centerOffset = prevOffset + ODD_OFFSET;
        int nextOffset = prevOffset + 1;
        horizontalStep(count, prevOffset, centerOffset, nextOffset, func);
    }

    template <typename F>
    void forEachVerticalEven(int columnOffset, const F &f) {
        if(SIZE_Y > 3) {
            int steps = SIZE_Y / 2 - 1;
            for(int i = 0; i < steps; i++) {
                int row = 2 + i * 2;
                T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
                T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
                f(prev, data[columnOffset + row * VERTICAL_STRIDE], next);
            }
        }
    }

    template <typename F>
    void forEachVerticalOdd(int columnOffset, const F &f) {
        int steps = (SIZE_Y - 1) / 2;
        for(int i = 0; i < steps; i++) {
            int row = i * 2 + 1;
            T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
            T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
            f(prev, data[columnOffset + row * VERTICAL_STRIDE], next);
        }
    }

    void scaleHorizontal(T evenScale, T oddScale, int firstLine, int numLines) {
        int offset = firstLine * VERTICAL_STRIDE;
        int count = numLines * VERTICAL_STRIDE;
        int steps = count / SIZE_X;
        int finalCount = count % SIZE_X;
        int finalOffset = count - finalCount;

        for(int i = 0; i < steps; i++) {
            data[threadIdx.x + i * SIZE_X + offset] *= evenScale;
            data[threadIdx.x + i * SIZE_X + offset + ODD_OFFSET] *= oddScale;
        }

        if(threadIdx.x < finalCount) {
            data[threadIdx.x + finalOffset + offset] *= evenScale;
            data[threadIdx.x + finalOffset + offset + ODD_OFFSET] *= oddScale;
        }
    }

    void scaleVertical(T evenScale, T oddScale, int columnOffset, int numLines, int firstLine) {
        for(int i = firstLine; i < (numLines + firstLine); i++) {
            if(i & 1) {
                data[columnOffset + i * VERTICAL_STRIDE] *= oddScale;
            } else {
                data[columnOffset + i * VERTICAL_STRIDE] *= evenScale;
            }
        }
    }
};

template <bool CHECKED>
class VerticalDWTPixelLoader {
protected:
    int end;
    int stride;
    int last;

    int initialize(int sizeX, int sizeY, int firstX, int firstY) {
        end = CHECKED ? (sizeY * sizeX + firstX) : 0;
        stride = sizeX;
        return firstX + sizeX * firstY;
    }

    void mirror(int &d, int sizeD) {
        if(d >= sizeD) {
            d = 2 * sizeD - 2 - d;
        } else if(d < 0) {
            d = -d;
        }
    }

public:
    void init(int sizeX, int sizeY, int firstX, int firstY) {
        mirror(firstX, sizeX);
        last = initialize(sizeX, sizeY, firstX, firstY) - sizeX;
    }

    void clear() {
        end = 0;
        stride = 0;
        last = 0;
    }

    template<typename T>
    T loadFrom(const T *input) {
        last += stride;
        if(CHECKED && (last == end)) {
            last -= 2 * stride;
            stride = -stride;
        }
        return input[last];
    }
};

template <bool CHECKED>
class VerticalDWTPixelWriter {
protected:
    int end;
    int stride;
    int next;

    int initialize(int sizeX, int sizeY, int firstX, int firstY) {
        end = CHECKED ? (sizeY * sizeX + firstX) : 0;
        stride = sizeX;
        return firstX + sizeX * firstY;
    }

public:
    void init(int sizeX, int sizeY, int firstX, int firstY) {
        if(firstX < sizeX) {
            next = initialize(sizeX, sizeY, firstX, firstY);
        } else {
            end = 0;
            stride = 0;
            next = 0;
        }
    }

    template<typename T>
    void writeInto(T *output, const T &value) {
        if((!CHECKED) || (next != end)) {
            output[next] = value;
            next += stride;
        }
    }
};

template <bool CHECKED>
class VerticalDWTBandLoader {
protected:
    int end;
    int strideHighToLow;
    int strideLowToHigh;
    int last;

    void mirror(int &d, int sizeD) {
        if(d >= sizeD) {
            d = 2 * sizeD - 2 - d;
        } else if(d < 0) {
            d = -d;
        }
    }

    int initialize(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        int columnOffset = firstX / 2;
        int verticalStride;

        if(firstX & 1) {
            verticalStride = imageSizeX / 2;
            columnOffset += DIVANDRND(imageSizeX, 2) * DIVANDRND(imageSizeY, 2);
            strideLowToHigh = (imageSizeX * imageSizeY) / 2;
        } else {
            verticalStride = imageSizeX / 2 + (imageSizeX & 1);
            strideLowToHigh = DIVANDRND(imageSizeY, 2) * imageSizeX;
        }

        strideHighToLow = verticalStride - strideLowToHigh;

        if(CHECKED) {
            end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * strideLowToHigh;
        } else {
            end = 0;
        }

        return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * strideLowToHigh;
    }

    template<typename T>
    T updateAndLoad(const T *input, int stride) {
        last += stride;
        if(CHECKED && (last == end)) {
            last -= (strideLowToHigh + strideHighToLow);
            int temp = strideLowToHigh;
            strideLowToHigh = -strideHighToLow;
            strideHighToLow = -temp;
        }
        return input[last];
    }

public:
    void init(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        mirror(firstX, imageSizeX);
        last = initialize(imageSizeX, imageSizeY, firstX, firstY);
        last -= (firstY & 1) ? strideLowToHigh : strideHighToLow;
    }

    void clear() {
        end = 0;
        strideHighToLow = 0;
        strideLowToHigh = 0;
        last = 0;
    }

    template<typename T>
    T loadLowFrom(const T *input) {
        return updateAndLoad(input, strideHighToLow);
    }

    template<typename T>
    T loadHighFrom(const T *input) {
        return updateAndLoad(input, strideLowToHigh);
    }
};

template <bool CHECKED>
class VerticalDWTBandWriter {
protected:
    int end;
    int strideHighToLow;
    int strideLowToHigh;
    int next;

    int initialize(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        int columnOffset = firstX / 2;
        int verticalStride;

        if(firstX & 1) {
            verticalStride = imageSizeX / 2;
            columnOffset += DIVANDRND(imageSizeX, 2) * DIVANDRND(imageSizeY, 2);
            strideLowToHigh = (imageSizeX * imageSizeY) / 2;
        } else {
            verticalStride = imageSizeX / 2 + (imageSizeX & 1);
            strideLowToHigh = DIVANDRND(imageSizeY, 2) * imageSizeX;
        }

        strideHighToLow = verticalStride - strideLowToHigh;

        if(CHECKED) {
            end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * strideLowToHigh;
        } else {
            end = 0;
        }

        return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * strideLowToHigh;
    }

    template<typename T>
    int saveAndUpdate(T *output, const T &item, int stride) {
        if((!CHECKED) || (next != end)) {
            output[next] = item;
            next += stride;
        }
        return next;
    }

public:
    void init(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        if (firstX < imageSizeX) {
            next = initialize(imageSizeX, imageSizeY, firstX, firstY);
        } else {
            clear();
        }
    }

    void clear() {
        end = 0;
        strideHighToLow = 0;
        strideLowToHigh = 0;
        next = 0;
    }

    template<typename T>
    int writeLowInto(T *output, const T &primary) {
        return saveAndUpdate(output, primary, strideLowToHigh);
    }

    template<typename T>
    int writeHighInto(T *output, const T &other) {
        return saveAndUpdate(output, other, strideHighToLow);
    }
};

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT53 {
private:
    template <bool CHECKED_LOADER>
    struct FDWT53Column {
        VerticalDWTPixelLoader<CHECKED_LOADER> loader;
        int offset;
        int pixel0, pixel1, pixel2;

        void clear() {
            offset = pixel0 = pixel1 = pixel2 = 0;
            loader.clear();
        }
    };

    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> FDWT53Buffer;
    FDWT53Buffer buffer;
    enum { STRIDE = FDWT53Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    void initColumn(FDWT53Column<CHECKED> &column, const int *input, int sizeX, int sizeY, int colIndex, int firstY) {
        column.offset = buffer.getColumnOffset(colIndex);
        int firstX = blockIdx.x * WIN_SIZE_X + colIndex;

        if(blockIdx.y == 0) {
            column.loader.init(sizeX, sizeY, firstX, firstY);
            column.pixel2 = column.loader.loadFrom(input);
            column.pixel1 = column.loader.loadFrom(input);
            column.pixel0 = column.loader.loadFrom(input);
            column.loader.init(sizeX, sizeY, firstX, firstY + 1);
        } else {
            column.loader.init(sizeX, sizeY, firstX, firstY - 2);
            column.pixel0 = column.loader.loadFrom(input);
            column.pixel1 = column.loader.loadFrom(input);
            column.pixel2 = column.loader.loadFrom(input);
        }
    }

    template <bool CHECKED>
    void loadAndVerticallyTransform(FDWT53Column<CHECKED> &column, const int *input) {
        buffer[column.offset + 0 * STRIDE] = column.pixel0;
        buffer[column.offset + 1 * STRIDE] = column.pixel1;
        buffer[column.offset + 2 * STRIDE] = column.pixel2;

        for(int i = 3; i < (3 + WIN_SIZE_Y); i++) {
            buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }

        column.pixel0 = buffer[column.offset + (WIN_SIZE_Y + 0) * STRIDE];
        column.pixel1 = buffer[column.offset + (WIN_SIZE_Y + 1) * STRIDE];
        column.pixel2 = buffer[column.offset + (WIN_SIZE_Y + 2) * STRIDE];

        buffer.forEachVerticalOdd(column.offset, Forward53Predict_op);
        buffer.forEachVerticalEven(column.offset, Forward53Update_op);
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const int *in, int *out, int sizeX, int sizeY, int winSteps) {
        FDWT53Column<CHECK_LOADS> column;
        FDWT53Column<CHECK_LOADS> boundaryColumn;
        int firstY = blockIdx.y * WIN_SIZE_Y * winSteps;
        initColumn(column, in, sizeX, sizeY, threadIdx.x, firstY);

        boundaryColumn.clear();
        if(threadIdx.x < 3) {
            int colId = threadIdx.x + ((threadIdx.x == 0) ? WIN_SIZE_X : -3);
            initColumn(boundaryColumn, in, sizeX, sizeY, colId, firstY);
        }

        int outColumnIndex = parityIdx<WIN_SIZE_X>();
        int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
        int outputFirstX = blockIdx.x * WIN_SIZE_X + outColumnIndex;
        VerticalDWTPixelWriter<CHECK_WRITES> writer;
        writer.init(sizeX, sizeY, outputFirstX, firstY);

        for(int w = 0; w < winSteps; w++) {
            loadAndVerticallyTransform(column, in);
            if(threadIdx.x < 3) {
                loadAndVerticallyTransform(boundaryColumn, in);
            }
            __syncthreads();

            buffer.forEachHorizontalOdd(2, WIN_SIZE_Y, Forward53Predict_op);
            __syncthreads();
            buffer.forEachHorizontalEven(2, WIN_SIZE_Y, Forward53Update_op);
            __syncthreads();

            for(int r = 2; r < (2 + WIN_SIZE_Y); r += 2) {
                writer.writeLowInto(out, buffer[outColumnOffset + r * STRIDE]);
                writer.writeHighInto(out, buffer[outColumnOffset + (r+1) * STRIDE]);
            }
            __syncthreads();
        }
    }

public:
    static void run(const int *in, int *out, int sx, int sy, int steps) {
        __shared__ FDWT53<WIN_SIZE_X, WIN_SIZE_Y> fdwt53;
        int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 1;
        int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 1;
        bool atRightBoundary = maxX >= sx;
        bool atBottomBoundary = maxY >= sy;

        if(atBottomBoundary) {
            fdwt53.transform<true, true>(in, out, sx, sy, steps);
        } else if(atRightBoundary) {
            fdwt53.transform<false, true>(in, out, sx, sy, steps);
        } else {
            fdwt53.transform<false, false>(in, out, sx, sy, steps);
        }
    }
};

