template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT97 {
private:
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> FDWT97Buffer;
    FDWT97Buffer buffer;
    enum { STRIDE = FDWT97Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct FDWT97ColumnLoadingInfo {
        VerticalDWTPixelLoader<CHECKED> loader;
        int offset;
    };

    void horizontalFDWT97(int lines, int firstLine) {
        __syncthreads();
        AddScaledSum s1 = {f97Predict1};
        buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        AddScaledSum s2 = {f97Update1};
        buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        AddScaledSum s3 = {f97Predict2};
        buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        AddScaledSum s4 = {f97Update2};
        buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        buffer.scaleHorizontal(scale97Div, scale97Mul, firstLine, lines);
        __syncthreads();
    }

    template <bool CHECKED>
    void initColumn(FDWT97ColumnLoadingInfo<CHECKED> &column, int columnIndex, const float *input, int sizeX, int sizeY, int firstY) {
        column.offset = buffer.getColumnOffset(columnIndex);
        int firstX = blockIdx.x * WIN_SIZE_X + columnIndex;

        if(blockIdx.y == 0) {
            column.loader.init(sizeX, sizeY, firstX, firstY);
            buffer[column.offset + 4 * STRIDE] = column.loader.loadFrom(input);
            buffer[column.offset + 3 * STRIDE] = buffer[column.offset + 5 * STRIDE] = column.loader.loadFrom(input);
            buffer[column.offset + 2 * STRIDE] = buffer[column.offset + 6 * STRIDE] = column.loader.loadFrom(input);
            buffer[column.offset + 1 * STRIDE] = column.loader.loadFrom(input);
            buffer[column.offset + 0 * STRIDE] = column.loader.loadFrom(input);
            column.loader.init(sizeX, sizeY, firstX, firstY + 3);
        } else {
            column.loader.init(sizeX, sizeY, firstX, firstY - 4);
            for(int i = 0; i < 7; i++) {
                buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
            }
        }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const float *input, FDWT97ColumnLoadingInfo<CHECKED> &column) {
        for(int i = 7; i < (7 + WIN_SIZE_Y); i++) {
            buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const float *in, float *out, int sizeX, int sizeY, int winSteps) {
        FDWT97ColumnLoadingInfo<CHECK_LOADS> loadedColumn;
        FDWT97ColumnLoadingInfo<CHECK_LOADS> boundaryColumn;
        int firstY = blockIdx.y * WIN_SIZE_Y * winSteps;
        initColumn(loadedColumn, threadIdx.x, in, sizeX, sizeY, firstY);

        boundaryColumn.offset = 0;
        boundaryColumn.loader.clear();
        if(threadIdx.x < 7) {
            int colId = threadIdx.x + ((threadIdx.x < 3) ? WIN_SIZE_X : -7);
            initColumn(boundaryColumn, colId, in, sizeX, sizeY, firstY);
        }

        horizontalFDWT97(7, 0);
        int outColumnIndex = parityIdx<WIN_SIZE_X>();
        int firstX = blockIdx.x * WIN_SIZE_X + outColumnIndex;
        VerticalDWTPixelWriter<CHECK_WRITES> writer;
        writer.init(sizeX, sizeY, firstX, firstY);
        int outColumnOffset = buffer.getColumnOffset(outColumnIndex);

        for(int w = 0; w < winSteps; w++) {
            loadWindowIntoColumn(in, loadedColumn);
            if(threadIdx.x < 7) {
                loadWindowIntoColumn(in, boundaryColumn);
            }
            horizontalFDWT97(WIN_SIZE_Y, 7);

            float last7Lines[7];
            for(int i = 0; i < 7; i++) {
                last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
            }

            AddScaledSum s1 = {f97Predict1};
            buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum_op);
            AddScaledSum s2 = {f97Update1};
            buffer.forEachVerticalEven(outColumnOffset, AddScaledSum_op);
            AddScaledSum s3 = {f97Predict2};
            buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum_op);
            AddScaledSum s4 = {f97Update2};
            buffer.forEachVerticalEven(outColumnOffset, AddScaledSum_op);

            for(int i = 4; i < (4 + WIN_SIZE_Y); i += 2) {
                writer.writeLowInto(out, buffer[outColumnOffset + i * STRIDE] * scale97Div);
                writer.writeHighInto(out, buffer[outColumnOffset + (i + 1) * STRIDE] * scale97Mul);
            }

            for(int i = 0; i < 7; i++) {
                buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
            }
            __syncthreads();
        }
    }

public:
    static void run(const float *input, float *output, int sx, int sy, int steps) {
        __shared__ FDWT97<WIN_SIZE_X, WIN_SIZE_Y> fdwt97;
        int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 3;
        int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 3;
        bool atRightBoundary = maxX >= sx;
        bool atBottomBoundary = sy <= maxY;

        if(atBottomBoundary) {
            fdwt97.transform<true, true>(input, output, sx, sy, steps);
        } else if(atRightBoundary) {
            fdwt97.transform<false, true>(input, output, sx, sy, steps);
        } else {
            fdwt97.transform<false, false>(input, output, sx, sy, steps);
        }
    }
};

