template <int WIN_SIZE_X, int WIN_SIZE_Y>
class RDWT97 {
private:
    template <bool CHECKED>
    struct RDWT97Column {
        VerticalDWTBandLoader<CHECKED> loader;
        int offset;
        void clear() {
            loader.clear();
            offset = 0;
        }
    };

    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> RDWT97Buffer;
    RDWT97Buffer buffer;
    enum { STRIDE = RDWT97Buffer::VERTICAL_STRIDE };

    void horizontalRDWT97(int lines, int firstLine) {
        __syncthreads();
        buffer.scaleHorizontal(scale97Mul, scale97Div, firstLine, lines);
        __syncthreads();
        AddScaledSum s1 = {r97update2};
        buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        AddScaledSum s2 = {r97predict2};
        buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        AddScaledSum s3 = {r97update1};
        buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum_op);
        __syncthreads();
        AddScaledSum s4 = {r97Predict1};
        buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum_op);
        __syncthreads();
    }

    template <bool CHECKED>
    void initColumn(int colIndex, const float *input, int sizeX, int sizeY, RDWT97Column<CHECKED> &column, int firstY) {
        int firstX = blockIdx.x * WIN_SIZE_X + colIndex;
        column.offset = buffer.getColumnOffset(colIndex);

        if(blockIdx.y == 0) {
            column.loader.init(sizeX, sizeY, firstX, firstY);
            buffer[column.offset + 3 * STRIDE] = column.loader.loadLowFrom(input);
            buffer[column.offset + 4 * STRIDE] = buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
            buffer[column.offset + 5 * STRIDE] = buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
            buffer[column.offset + 6 * STRIDE] = buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        } else {
            column.loader.init(sizeX, sizeY, firstX, firstY - 3);
            buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
            buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
            buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
            buffer[column.offset + 3 * STRIDE] = column.loader.loadLowFrom(input);
            buffer[column.offset + 4 * STRIDE] = column.loader.loadHighFrom(input);
            buffer[column.offset + 5 * STRIDE] = column.loader.loadLowFrom(input);
            buffer[column.offset + 6 * STRIDE] = column.loader.loadHighFrom(input);
        }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(RDWT97Column<CHECKED> &col, const float *input) {
        for(int i = 7; i < (7 + WIN_SIZE_Y); i += 2) {
            buffer[col.offset + i * STRIDE] = col.loader.loadLowFrom(input);
            buffer[col.offset + (i + 1) * STRIDE] = col.loader.loadHighFrom(input);
        }
    }

    template <bool CHECKED_LOADS, bool CHECKED_WRITES>
    void transform(const float *in, float *out, int sizeX, int sizeY, int winSteps) {
        RDWT97Column<CHECKED_LOADS> column;
        RDWT97Column<CHECKED_LOADS> boundaryColumn;
        int firstY = blockIdx.y * WIN_SIZE_Y * winSteps;

        boundaryColumn.clear();
        if(threadIdx.x < 7) {
            int colId = threadIdx.x + ((threadIdx.x < 4) ? WIN_SIZE_X : -7);
            initColumn(colId, in, sizeX, sizeY, boundaryColumn, firstY);
        }

        initColumn(parityIdx<WIN_SIZE_X>(), in, sizeX, sizeY, column, firstY);
        horizontalRDWT97(7, 0);

        int outputX = blockIdx.x * WIN_SIZE_X + threadIdx.x;
        VerticalDWTPixelWriter<CHECKED_WRITES> writer;
        writer.init(sizeX, sizeY, outputX, firstY);
        int outColumnOffset = buffer.getColumnOffset(threadIdx.x);

        for(int w = 0; w < winSteps; w++) {
            loadWindowIntoColumn(column, in);
            if(threadIdx.x < 7) {
                loadWindowIntoColumn(boundaryColumn, in);
            }
            horizontalRDWT97(WIN_SIZE_Y, 7);

            float last7Lines[7];
            for(int i = 0; i < 7; i++) {
                last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
            }

            buffer.scaleVertical(scale97Div, scale97Mul, outColumnOffset, WIN_SIZE_Y + 7, 0);
            AddScaledSum s1 = {r97update2};
            buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum_op);
            AddScaledSum s2 = {r97predict2};
            buffer.forEachVerticalEven(outColumnOffset, AddScaledSum_op);
            AddScaledSum s3 = {r97update1};
            buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum_op);
            AddScaledSum s4 = {r97Predict1};
            buffer.forEachVerticalEven(outColumnOffset, AddScaledSum_op);

            for(int i = 3; i < (3 + WIN_SIZE_Y); i++) {
                writer.writeInto(out, buffer[outColumnOffset + i * STRIDE]);
            }

            for(int i = 0; i < 7; i++) {
                buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
            }
            __syncthreads();
        }
    }

public:
    static void run(const float *input, float *output, int sx, int sy, int steps) {
        __shared__ RDWT97<WIN_SIZE_X, WIN_SIZE_Y> rdwt97;
        int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 3;
        int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 3;
        bool atRightBoundary = maxX >= sx;
        bool atBottomBoundary = maxY >= sy;

        if(atBottomBoundary) {
            rdwt97.transform<true, true>(input, output, sx, sy, steps);
        } else if(atRightBoundary) {
            rdwt97.transform<false, true>(input, output, sx, sy, steps);
        } else {
            rdwt97.transform<false, false>(input, output, sx, sy, steps);
        }
    }
};

