static inline void Forward53Predict_op(int p, int *c, int n) {
    *c -= (p + n) / 2;
}

static inline void Forward53Update_op(int p, int *c, int n) {
    *c += (p + n + 2) / 4;
}

static inline void Reverse53Update_op(int p, int *c, int n) {
    *c -= (p + n + 2) / 4;
}

static inline void Reverse53Predict_op(int p, int *c, int n) {
    *c = *c + ((p + n) / 2);
}

static inline void AddScaledSum_op(AddScaledSum self, float p, float *c, float n) {
    *c += self.scale * (p + n);
}

