void setupOpenCL() {
    cl_int err;
    cl_uint numPlatforms;
    cl_platform_id* platforms;

    err = clGetPlatformIDs(0, NULL, &numPlatforms);
    checkCLError(err, "Getting platform IDs");

    if (numPlatforms == 0) {
        fprintf(stderr, "No OpenCL platforms found\n");
        exit(1);
    }

    platforms = (cl_platform_id*)malloc(numPlatforms * sizeof(cl_platform_id));
    err = clGetPlatformIDs(numPlatforms, platforms, NULL);
    checkCLError(err, "Getting platform IDs");

    cl_device_id device = NULL;
    err = clGetDeviceIDs(platforms[0], CL_DEVICE_TYPE_GPU, 1, &device, NULL);
    if (err != CL_SUCCESS) {
        err = clGetDeviceIDs(platforms[0], CL_DEVICE_TYPE_CPU, 1, &device, NULL);
    }
    if (err != CL_SUCCESS) {
        err = clGetDeviceIDs(platforms[0], CL_DEVICE_TYPE_ALL, 1, &device, NULL);
    }
    checkCLError(err, "Getting device ID");

    cl_context_properties props[] = {CL_CONTEXT_PLATFORM, (cl_context_properties)platforms[0], 0};
    context = clCreateContext(props, 1, &device, NULL, NULL, &err);
    checkCLError(err, "Creating context");

    commandQueue = clCreateCommandQueue(context, device, 0, &err);
    checkCLError(err, "Creating command queue");

    free(platforms);

    const char* kernelSource = 
        "__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t) {\n"
        "    int idx = get_global_id(0);\n"
        "    if (idx >= Size-1-t) return;\n"
        "    m_cuda[Size*(idx+t+1)+t] = a_cuda[Size*(idx+t+1)+t] / a_cuda[Size*t+t];\n"
        "}\n"
        "\n"
        "__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t) {\n"
        "    int xidx = get_global_id(0);\n"
        "    int yidx = get_global_id(1);\n"
        "    if (xidx >= Size-1-t) return;\n"
        "    if (yidx >= Size-t) return;\n"
        "    a_cuda[Size*(xidx+1+t)+(yidx+t)] -= m_cuda[Size*(xidx+1+t)+t] * a_cuda[Size*t+(yidx+t)];\n"
        "    if (yidx == 0) {\n"
        "        b_cuda[xidx+1+t] -= m_cuda[Size*(xidx+1+t)+t] * b_cuda[t];\n"
        "    }\n"
        "}\n";

    program = clCreateProgramWithSource(context, 1, &kernelSource, NULL, &err);
    checkCLError(err, "Creating program");

    err = clBuildProgram(program, 0, NULL, NULL, NULL, NULL);
    if (err != CL_SUCCESS) {
        size_t log_size;
        clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, 0, NULL, &log_size);
        char* log = (char*)malloc(log_size + 1);
        clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, log_size, log, NULL);
        log[log_size] = '\0';
        fprintf(stderr, "Build error: %s\n", log);
        free(log);
        exit(1);
    }

    kernelFan1 = clCreateKernel(program, "Fan1", &err);
    checkCLError(err, "Creating Fan1 kernel");
    kernelFan2 = clCreateKernel(program, "Fan2", &err);
    checkCLError(err, "Creating Fan2 kernel");
}

void ForwardSub()
{
	int t;
    cl_mem m_cl, a_cl, b_cl;
    cl_int err;

    setupOpenCL();

    // Create buffers
    m_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &err);
    checkCLError(err, "Creating m buffer");
    a_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &err);
    checkCLError(err, "Creating a buffer");
    b_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * sizeof(float), NULL, &err);
    checkCLError(err, "Creating b buffer");

    // Copy data to device
    clEnqueueWriteBuffer(commandQueue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
    clEnqueueWriteBuffer(commandQueue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
    clEnqueueWriteBuffer(commandQueue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);

    int block_size, grid_size;

    block_size = MAXBLOCKSIZE;
    if (block_size > Size) block_size = Size;
    grid_size = (Size + block_size - 1) / block_size;

    size_t globalSize1 = ((size_t)grid_size) * block_size;
    size_t localSize1 = block_size;

    int blockSize2d, gridSize2d;
    blockSize2d = BLOCK_SIZE_XY;
    if (blockSize2d > Size) blockSize2d = Size;
    gridSize2d = (Size + blockSize2d - 1) / blockSize2d; 

    size_t globalSize2[2] = {(size_t)gridSize2d * blockSize2d, (size_t)gridSize2d * blockSize2d};
    size_t localSize2[2] = {blockSize2d, blockSize2d};

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    struct timeval time_start;
    gettimeofday(&time_start, NULL);

    for (t=0; t<(Size-1); t++) {
        // Set arguments for Fan1
        clSetKernelArg(kernelFan1, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernelFan1, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernelFan1, 2, sizeof(int), &Size);
        clSetKernelArg(kernelFan1, 3, sizeof(int), &t);

        err = clEnqueueExecuteKernel(commandQueue, kernelFan1, 1, &localSize1, &globalSize1, NULL, 0, NULL, NULL);
        checkCLError(err, "Executing Fan1");
        clFinish(commandQueue);

        // Set arguments for Fan2
        clSetKernelArg(kernelFan2, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernelFan2, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernelFan2, 2, sizeof(cl_mem), &b_cl);
        clSetKernelArg(kernelFan2, 3, sizeof(int), &Size);
        int j1_val = Size - t;
        clSetKernelArg(kernelFan2, 4, sizeof(int), &j1_val);
        clSetKernelArg(kernelFan2, 5, sizeof(int), &t);

        err = clEnqueueExecuteKernel(commandQueue, kernelFan2, 2, localSize2, globalSize2, NULL, 0, NULL, NULL);
        checkCLError(err, "Executing Fan2");
        clFinish(commandQueue);
    }

    struct timeval time_end;
    gettimeofday(&time_end, NULL);
    totalKernelTime = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

#ifdef  TIMING
    tvsub(&time_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy data back
    clEnqueueReadBuffer(commandQueue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
    clEnqueueReadBuffer(commandQueue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
    clEnqueueReadBuffer(commandQueue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);

    clReleaseMemObject(m_cl);
    clReleaseMemObject(a_cl);
    clReleaseMemObject(b_cl);
}






void BackSub()
{

	finalVec = (float *) malloc(Size * sizeof(float));

	int i,j;
	for(i=0;i<Size;i++){
		finalVec[Size-i-1]=b[Size-i-1];
		for(j=0;j<i;j++)
		{
			finalVec[Size-i-1]-=*(a+Size*(Size-i-1)+(Size-j-1)) * finalVec[Size-j-1];
		}
		finalVec[Size-i-1]=finalVec[Size-i-1]/ *(a+Size*(Size-i-1)+(Size-i-1));
	}
}

