void checkOpenCLError(const char *msg, cl_int err)
{
    if( CL_SUCCESS != err) 
    {
        fprintf(stderr, "OpenCL error: %s: %d.\n", msg, err);
        exit(EXIT_FAILURE);
    }                         
}

#define MAXBLOCKSIZE 512
#define BLOCK_SIZE_XY 4

__kernel void Fan1(float *m, float *a, int Size, int t)
{   
    int idx = get_global_id(0);
    if(idx >= Size-1-t) return;

    m[Size*(idx+t+1)+t] = a[Size*(idx+t+1)+t] / a[Size*t+t];
}

__kernel void Fan2(float *m, float *a, float *b, int Size, int j1, int t)
{
    int xidx = get_global_id(0);
    int yidx = get_global_id(1);

    if(xidx >= Size-1-t) return;
    if(yidx >= Size-t) return;

    float m_val = m[Size*(xidx+1+t)+t];
    float a_diag = a[Size*t+(yidx+t)];
    float a_target = a[Size*(xidx+1+t)+(yidx+t)];
    a[Size*(xidx+1+t)+(yidx+t)] = a_target - m_val * a_diag;

    if(yidx == 0){
        b[xidx+1+t] -= m[Size*(xidx+1+t)+t] * b[t];
    }
}

