    checkCLError("Create Program", err);

    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    checkCLError("Build Program", err);

    kernel_fan1 = clCreateKernel(program, "Fan1", &err);
    checkCLError("Create Kernel Fan1", err);

    kernel_fan2 = clCreateKernel(program, "Fan2", &err);
    checkCLError("Create Kernel Fan2", err);

