    size_t global_size_2_x = (size_t)gridSize2d * blockSize2d;
    size_t global_size_2_y = (size_t)gridSize2d * blockSize2d;

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    struct timeval time_start;
    gettimeofday(&time_start, NULL);

    for (t=0; t<(Size-1); t++) {
        int arg_j1 = Size - t;
        int range_x = Size - 1 - t;
