        size_t current_gs_1 = (range_x > 0) ? ((range_x + block_size - 1) / block_size) * block_size : 1;
        size_t current_gs_2_x = (range_x > 0) ? ((range_x + blockSize2d - 1) / blockSize2d) * blockSize2d : 1;
        size_t current_gs_2_y = (range_y > 0) ? ((range_y + blockSize2d - 1) / blockSize2d) * blockSize2d : 1;

