            // No work to do for Fan1/Fan2 in this step if range is 0 or negative
            continue;
        }

        clSetKernelArg(kernel_fan1, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernel_fan1, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernel_fan1, 2, sizeof(int), &Size);
        clSetKernelArg(kernel_fan1, 3, sizeof(int), &t);

        err = clEnqueueRunKernel(queue, kernel_fan1, 1, NULL, &current_gs_1, NULL, 0, NULL, NULL);
        checkCLError("Run Kernel Fan1", err);

