        checkCLError("Run Kernel Fan2", err);

        clFinish(queue);
    }

    struct timeval time_end;
    gettimeofday(&time_end, NULL);
    totalKernelTime = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

#ifdef  TIMING
    tvsub(&time_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    clEnqueueReadBuffer(queue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
    clEnqueueReadBuffer(queue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
    clEnqueueReadBuffer(queue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);

    clReleaseMemObject(m_cl);
    clReleaseMemObject(a_cl);
    clReleaseMemObject(b_cl);
    clReleaseKernel(kernel_fan1);
    clReleaseKernel(kernel_fan2);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);
}






