        } else if (1 == tx) {
            in_sqr_final_sum = 0;
            for (i = 0; i < in_sqr_cols; i++) {
                in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx == 0) {
            mean = in_final_sum / in_elem;
            mean_sqr = mean * mean;
            variance = (in_sqr_final_sum / in_elem) - mean_sqr;
            deviation = sqrt(variance);
            denomT = sqrt((float)(in_elem - 1)) * deviation;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while (ei_new < in2_sub2_elem) {
            d_in2_sqr_sub2[ei_new] = d_in2_sqr_sub2[ei_new] * denomT;
            ei_new = ei_new + 256;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while (ei_new < conv_elem) {
            d_conv[ei_new] = d_conv[ei_new] - d_in2_sub2[ei_new] * in_final_sum / in_elem;
            ei_new = ei_new + 256;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while (ei_new < in2_sub2_elem) {
            d_in2_sqr_sub2[ei_new] = d_conv[ei_new] / d_in2_sqr_sub2[ei_new];
            ei_new = ei_new + 256;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        cent = sSize + tSize + 1;
        if (frame_no == 0) {
            tMask_row = cent + d_Row[point_no] - d_Row[point_no] - 1;
            tMask_col = cent + d_Col[point_no] - d_Col[point_no] - 1;
        } else {
            pointer = frame_no - 1 + point_no * no_frames;
            tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
            tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;
        }

        ei_new = tx;
        while (ei_new < tMask_elem) {
            location = tMask_col * tMask_rows + tMask_row;
            if (location == ei_new) {
                d_tMask[ei_new] = 1;
            } else {
                d_tMask[ei_new] = 0;
            }
            ei_new = ei_new + 256;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while (ei_new < mask_conv_elem) {
            ic = (ei_new + 1) % mask_conv_rows;
            jc = (ei_new + 1) / mask_conv_rows + 1;
            if ((ei_new + 1) % mask_conv_rows == 0) {
                ic = mask_conv_rows;
                jc -= 1;
            }

            j = jc + mask_conv_joffset;
            jp1 = j + 1;
            if (mask_cols < jp1) {
                ja1 = jp1 - mask_cols;
            } else {
                ja1 = 1;
            }
            if (tMask_cols < j) {
                ja2 = tMask_cols;
            } else {
                ja2 = j;
            }

            i = ic + mask_conv_ioffset;
            ip1 = i + 1;

            if (mask_rows < ip1) {
                ia1 = ip1 - mask_rows;
            } else {
                ia1 = 1;
            }
            if (tMask_rows < i) {
                ia2 = tMask_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for (ja = ja1; ja2 >= ja; ja++) {
                jb = jp1 - ja;
                for (ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + d_tMask[tMask_rows * (ja - 1) + ia - 1] * 1;
                }
            }

            d_mask_conv[ei_new] = d_in2_sqr_sub2[ei_new] * s;
            ei_new = ei_new + 256;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while (ei_new < mask_conv_rows) {
            largest_coordinate_current = -1;
            largest_value_current = -1;
            for (i = 0; i < mask_conv_cols; i++) {
                int idx = ei_new * mask_conv_rows + i;
                float val = fabs(d_mask_conv[idx]);
                if (largest_value < val) {
                    largest_coordinate = idx;
                    largest_value = val;
                }
            }
            par_max_coo[ei_new] = largest_coordinate;
            par_max_val[ei_new] = largest_value;
            ei_new = ei_new + 256;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (0 == tx) {
            fin_max_val = -1;
            fin_max_coo = -1;
            for (i = 0; i < mask_conv_rows; i++) {
                if (fin_max_val < par_max_val[i]) {
                    fin_max_val = par_max_val[i];
                    fin_max_coo = par_max_coo[i];
                }
            }

            largest_row = (fin_max_coo + 1) % mask_conv_rows - 1;
            largest_col = (fin_max_coo + 1) / mask_conv_rows;
            if ((fin_max_coo + 1) % mask_conv_rows == 0) {
                largest_row = mask_conv_rows - 1;
                largest_col -= 1;
            }

            largest_row = largest_row + 1;
            largest_col += 1;
            offset_row = largest_row - in_rows - (sSize - tSize);
            offset_col = largest_col - in_cols - (sSize - tSize);
            pointer = frame_no + point_no * no_frames;
            d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
            d_tColLoc[pointer] = d_Col[point_no] + offset_col;
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (frame_no != 0 && (frame_no % 10 == 0)) {
        loc_pointer = point_no * no_frames + frame_no;
        d_Row[point_no] = d_tRowLoc[loc_pointer];
        d_Col[point_no] = d_tColLoc[loc_pointer];

        ei_new = tx;
        while (ei_new < in_elem) {
            row = (ei_new + 1) % in_rows - 1;
            col = (ei_new + 1) / in_rows + 1 - 1;
            if ((ei_new + 1) % in_rows == 0) {
                row = in_rows - 1;
                col -= 1;
            }

            ori_row = d_Row[point_no] - 25 + row - 1;
            ori_col = d_Col[point_no] - 25 + col - 1;
            ori_pointer = ori_col * frame_rows + ori_row;

            d_in[ei_new] = alpha * d_in[ei_new] + (1.00 - alpha) * d_frame[ori_pointer];

            ei_new = ei_new + 256;
        }
    }
}

