#define NUMBER_THREADS 256

kernel void kernel(
    global const params_common_change* d_common_change_ptr,
    global const params_common* d_common_ptr,
    global params_unique* d_unique_ptr) {

    params_common_change d_common_change = *d_common_change_ptr;
    params_common d_common = *d_common_ptr;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei_new;

    float* d_in;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    float s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    float sum;
    int pos_ori;
    float temp;
    float temp2;
    int location;
    int cent;
    int tMask_row; 
    int tMask_col;
    float largest_value_current = 0;
    float largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    float fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;

    local float in_partial_sum[51];
    local float in_sqr_partial_sum[51];
    local float in_final_sum;
    local float in_sqr_final_sum;
    float mean;
    float mean_sqr;
    float variance;
    float deviation;
    local float denomT;
    local float par_max_val[131];
    local int par_max_coo[131];
    int pointer;
    local float d_in_mod_temp[2601];
    int ori_pointer;
    int loc_pointer;

    if(d_common_change.frame_no == 0){
        d_in = &d_unique_ptr[bx].d_T[d_unique_ptr[bx].in_pointer];

        ei_new = tx;
        if(0 == ei_new){
            pointer = d_unique_ptr[bx].point_no*d_common.no_frames+d_common_change.frame_no;
            d_unique_ptr[bx].d_tRowLoc[pointer] = d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no];
            d_unique_ptr[bx].d_tColLoc[pointer] = d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no];
        }

        ei_new = tx;
        while(ei_new < d_common.in_elem){
            row = (ei_new+1) % d_common.in_rows - 1;
            col = (ei_new+1) / d_common.in_rows + 1 - 1;
            if((ei_new+1) % d_common.in_rows == 0){
                row = d_common.in_rows - 1;
                col -= 1;
            }

            ori_row = d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] - 25 + row - 1;
            ori_col = d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col*d_common.frame_rows+ori_row;

            d_in[col*d_common.in_rows+row] = d_common_change.d_frame[ori_pointer];

            ei_new = ei_new + NUMBER_THREADS;
        }
    }

    if(d_common_change.frame_no != 0){
        in2_rowlow = d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] - d_common.sSize;
        in2_collow = d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] - d_common.sSize;

        ei_new = tx;
        while(ei_new < d_common.in2_elem){
            row = (ei_new+1) % d_common.in2_rows - 1;
            col = (ei_new+1) / d_common.in2_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_rows == 0){
                row = d_common.in2_rows - 1;
                col -= 1;
            }

            ori_row = row + in2_rowlow - 1;
            ori_col = col + in2_collow - 1;
            d_unique_ptr[bx].d_in2[ei_new] = d_common_change.d_frame[ori_col*d_common.frame_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        d_in = &d_unique_ptr[bx].d_T[d_unique_ptr[bx].in_pointer];

        ei_new = tx;
        while(ei_new < d_common.in_elem){
            row = (ei_new+1) % d_common.in_rows - 1;
            col = (ei_new+1) / d_common.in_rows + 1 - 1;
            if((ei_new+1) % d_common.in_rows == 0){
                row = d_common.in_rows - 1;
                col -= 1;
            }

            rot_row = (d_common.in_rows-1) - row;
            rot_col = (d_common.in_rows-1) - col;
            d_in_mod_temp[ei_new] = d_in[rot_col*d_common.in_rows+rot_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.conv_elem){
            ic = (ei_new+1) % d_common.conv_rows;
            jc = (ei_new+1) / d_common.conv_rows + 1;
            if((ei_new+1) % d_common.conv_rows == 0){
                ic = d_common.conv_rows;
                jc -= 1;
            }

            j = jc + d_common.joffset;
            jp1 = j + 1;
            if(d_common.in2_cols < jp1){
                ja1 = jp1 - d_common.in2_cols;
            }
            else{
                ja1 = 1;
            }
            if(d_common.in_cols < j){
                ja2 = d_common.in_cols;
            }
            else{
                ja2 = j;
            }

            i = ic + d_common.ioffset;
            ip1 = i + 1;

            if(d_common.in2_rows < ip1){
                ia1 = ip1 - d_common.in2_rows;
            }
            else{
                ia1 = 1;
            }
            if(d_common.in_rows < i){
                ia2 = d_common.in_rows;
            }
            else{
                ia2 = i;
            }

            s = 0;

            for(ja=ja1; ja2 >= ja; ja++){
                jb = jp1 - ja;
                for(ia=ia1; ia2 >= ia; ia++){
                    ib = ip1 - ia;
                    s = s + d_in_mod_temp[d_common.in_rows*(ja-1)+ia-1] * d_unique_ptr[bx].d_in2[d_common.in2_rows*(jb-1)+ib-1];
                }
            }

            d_unique_ptr[bx].d_conv[ei_new] = s;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_elem){
            row = (ei_new+1) % d_common.in2_pad_cumv_rows - 1;
            col = (ei_new+1) / d_common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_pad_cumv_rows == 0){
                row = d_common.in2_pad_cumv_rows - 1;
                col -= 1;
            }

            if(	row > (d_common.in2_pad_add_rows-1) &&														
                row < (d_common.in2_pad_add_rows+d_common.in2_rows) && 
                col > (d_common.in2_pad_add_cols-1) && 
                col < (d_common.in2_pad_add_cols+d_common.in2_cols)){
                ori_row = row - d_common.in2_pad_add_rows;
                ori_col = col - d_common.in2_pad_add_cols;
                d_unique_ptr[bx].d_in2_pad_cumv[ei_new] = d_unique_ptr[bx].d_in2[ori_col*d_common.in2_rows+ori_row];
            }
            else{																			
                d_unique_ptr[bx].d_in2_pad_cumv[ei_new] = 0;
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_cols){
            pos_ori = ei_new*d_common.in2_pad_cumv_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori+d_common.in2_pad_cumv_rows; position += 1){
                d_unique_ptr[bx].d_in2_pad_cumv[position] = d_unique_ptr[bx].d_in2_pad_cumv[position] + sum;
                sum = d_unique_ptr[bx].d_in2_pad_cumv[position];
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_sel_elem){
            row = (ei_new+1) % d_common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new+1) / d_common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_pad_cumv_sel_rows == 0){
                row = d_common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
            d_unique_ptr[bx].d_in2_pad_cumv_sel[ei_new] = d_unique_ptr[bx].d_in2_pad_cumv[ori_col*d_common.in2_pad_cumv_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_elem){
            row = (ei_new+1) % d_common.in2_sub_cumh_rows - 1;
            col = (ei_new+1) / d_common.in2_sub_cumh_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_sub_cumh_rows == 0){
                row = d_common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
            d_unique_ptr[bx].d_in2_sub_cumh[ei_new] = d_unique_ptr[bx].d_in2_pad_cumv[ori_col*d_common.in2_pad_cumv_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_elem){
            d_unique_ptr[bx].d_in2_sub_cumh[ei_new] = d_unique_ptr[bx].d_in2_pad_cumv_sel[ei_new] - d_unique_ptr[bx].d_in2_sub_cumh[ei_new];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_rows){
            pos_ori = ei_new;

            sum = 0;

            for(position = pos_ori; position < pos_ori+d_common.in2_sub_cumh_elem; position = position + d_common.in2_sub_cumh_rows){
                d_unique_ptr[bx].d_in2_sub_cumh[position] = d_unique_ptr[bx].d_in2_sub_cumh[position] + sum;
                sum = d_unique_ptr[bx].d_in2_sub_cumh[position];
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_sel_elem){
            row = (ei_new+1) % d_common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new+1) / d_common.in2_sub_cumh_sel_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_sub_cumh_sel_rows == 0){
                row = d_common.in2_sub_cumh_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
            d_unique_ptr[bx].d_in2_sub_cumh_sel[ei_new] = d_unique_ptr[bx].d_in2_sub_cumh[ori_col*d_common.in2_sub_cumh_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            row = (ei_new+1) % d_common.in2_sub2_rows - 1;
            col = (ei_new+1) / d_common.in2_sub2_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_sub2_rows == 0){
                row = d_common.in2_sub2_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
            d_unique_ptr[bx].d_in2_sub2[ei_new] = d_unique_ptr[bx].d_in2_sub_cumh[ori_col*d_common.in2_sub_cumh_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            d_unique_ptr[bx].d_in2_sub2[ei_new] = d_unique_ptr[bx].d_in2_sub_cumh_sel[ei_new] - d_unique_ptr[bx].d_in2_sub2[ei_new];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sqr_elem){
            temp = d_unique_ptr[bx].d_in2[ei_new];
            d_unique_ptr[bx].d_in2_sqr[ei_new] = temp * temp;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_elem){
            row = (ei_new+1) % d_common.in2_pad_cumv_rows - 1;
            col = (ei_new+1) / d_common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_pad_cumv_rows == 0){
                row = d_common.in2_pad_cumv_rows - 1;
                col -= 1;
            }

            if(	row > (d_common.in2_pad_add_rows-1) &&													
                row < (d_common.in2_pad_add_rows+d_common.in2_sqr_rows) && 
                col > (d_common.in2_pad_add_cols-1) && 
                col < (d_common.in2_pad_add_cols+d_common.in2_sqr_cols)){
                ori_row = row - d_common.in2_pad_add_rows;
                ori_col = col - d_common.in2_pad_add_cols;
                d_unique_ptr[bx].d_in2_pad_cumv[ei_new] = d_unique_ptr[bx].d_in2_sqr[ori_col*d_common.in2_sqr_rows+ori_row];
            }
            else{																							
                d_unique_ptr[bx].d_in2_pad_cumv[ei_new] = 0;
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_cols){
            pos_ori = ei_new*d_common.in2_pad_cumv_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori+d_common.in2_pad_cumv_rows; position += 1){
                d_unique_ptr[bx].d_in2_pad_cumv[position] = d_unique_ptr[bx].d_in2_pad_cumv[position] + sum;
                sum = d_unique_ptr[bx].d_in2_pad_cumv[position];
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_pad_cumv_sel_elem){
            row = (ei_new+1) % d_common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new+1) / d_common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_pad_cumv_sel_rows == 0){
                row = d_common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
            d_unique_ptr[bx].d_in2_pad_cumv_sel[ei_new] = d_unique_ptr[bx].d_in2_pad_cumv[ori_col*d_common.in2_pad_cumv_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_elem){
            row = (ei_new+1) % d_common.in2_sub_cumh_rows - 1;
            col = (ei_new+1) / d_common.in2_sub_cumh_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_sub_cumh_rows == 0){
                row = d_common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
            d_unique_ptr[bx].d_in2_sub_cumh[ei_new] = d_unique_ptr[bx].d_in2_pad_cumv[ori_col*d_common.in2_pad_cumv_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_elem){
            d_unique_ptr[bx].d_in2_sub_cumh[ei_new] = d_unique_ptr[bx].d_in2_pad_cumv_sel[ei_new] - d_unique_ptr[bx].d_in2_sub_cumh[ei_new];

            ei_new = ei_new + NUMBER_THREADS;
        }

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_rows){
            pos_ori = ei_new;

            sum = 0;

            for(position = pos_ori; position < pos_ori+d_common.in2_sub_cumh_elem; position = position + d_common.in2_sub_cumh_rows){
                d_unique_ptr[bx].d_in2_sub_cumh[position] = d_unique_ptr[bx].d_in2_sub_cumh[position] + sum;
                sum = d_unique_ptr[bx].d_in2_sub_cumh[position];
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub_cumh_sel_elem){
            row = (ei_new+1) % d_common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new+1) / d_common.in2_sub_cumh_sel_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_sub_cumh_sel_rows == 0){
                row = d_common.in2_sub_cumh_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
            d_unique_ptr[bx].d_in2_sub_cumh_sel[ei_new] = d_unique_ptr[bx].d_in2_sub_cumh[ori_col*d_common.in2_sub_cumh_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            row = (ei_new+1) % d_common.in2_sub2_rows - 1;
            col = (ei_new+1) / d_common.in2_sub2_rows + 1 - 1;
            if((ei_new+1) % d_common.in2_sub2_rows == 0){
                row = d_common.in2_sub2_rows - 1;
                col -= 1;
            }

            ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
            d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] = d_unique_ptr[bx].d_in2_sub_cumh[ori_col*d_common.in2_sub_cumh_rows+ori_row];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] = d_unique_ptr[bx].d_in2_sub_cumh_sel[ei_new] - d_unique_ptr[bx].d_in2_sqr_sub2[ei_new];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            temp = d_unique_ptr[bx].d_in2_sub2[ei_new];
            temp2 = d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] - (temp * temp / d_common.in_elem);
            if(0 > temp2){
                temp2 = 0;
            }
            d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] = sqrt(temp2);

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in_sqr_elem){
            temp = d_in[ei_new];
            d_unique_ptr[bx].d_in_sqr[ei_new] = temp * temp;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in_cols){
            sum = 0;
            for(i = 0; i < d_common.in_rows; i++){
                sum = sum + d_in[ei_new*d_common.in_rows+i];
            }
            in_partial_sum[ei_new] = sum;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in_sqr_rows){
            sum = 0;
            for(i = 0; i < d_common.in_sqr_cols; i++){
                sum = sum + d_unique_ptr[bx].d_in_sqr[ei_new+d_common.in_sqr_rows*i];
            }
            in_sqr_partial_sum[ei_new] = sum;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if(0 == tx){
            in_final_sum = 0;
            for(i = 0; i<d_common.in_cols; i++){
                in_final_sum = in_final_sum + in_partial_sum[i];
            }
        }else if(1 == tx){
            in_sqr_final_sum = 0;
            for(i = 0; i<d_common.in_sqr_cols; i++){
                in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if(0 == tx){
            mean = in_final_sum / d_common.in_elem;
            mean_sqr = mean * mean;
            variance  = (in_sqr_final_sum / d_common.in_elem) - mean_sqr;
            deviation = sqrt(variance);

            denomT = sqrt((float)(d_common.in_elem-1))*deviation;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] = d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] * denomT;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.conv_elem){
            d_unique_ptr[bx].d_conv[ei_new] = d_unique_ptr[bx].d_conv[ei_new] - d_unique_ptr[bx].d_in2_sub2[ei_new] * in_final_sum / d_common.in_elem;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.in2_sub2_elem){
            d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] = d_unique_ptr[bx].d_conv[ei_new] / d_unique_ptr[bx].d_in2_sqr_sub2[ei_new];

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        cent = d_common.sSize + d_common.tSize + 1;
        if(d_common_change.frame_no == 0){
            tMask_row = cent + d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] - d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] - 1;
            tMask_col = cent + d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] - d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] - 1;
        }
        else{
            pointer = d_common_change.frame_no-1+d_unique_ptr[bx].point_no*d_common.no_frames;
            tMask_row = cent + d_unique_ptr[bx].d_tRowLoc[pointer] - d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] - 1;
            tMask_col = cent + d_unique_ptr[bx].d_tColLoc[pointer] - d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] - 1;
        }

        ei_new = tx;
        while(ei_new < d_common.tMask_elem){
            location = tMask_col*d_common.tMask_rows + tMask_row;

            if(location == ei_new){
                d_unique_ptr[bx].d_tMask[ei_new] = 1;
            }
            else{
                d_unique_ptr[bx].d_tMask[ei_new] = 0;
            }

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.mask_conv_elem){
            ic = (ei_new+1) % d_common.mask_conv_rows;
            jc = (ei_new+1) / d_common.mask_conv_rows + 1;
            if((ei_new+1) % d_common.mask_conv_rows == 0){
                ic = d_common.mask_conv_rows;
                jc -= 1;
            }

            j = jc + d_common.mask_conv_joffset;
            jp1 = j + 1;
            if(d_common.mask_cols < jp1){
                ja1 = jp1 - d_common.mask_cols;
            }
            else{
                ja1 = 1;
            }
            if(d_common.tMask_cols < j){
                ja2 = d_common.tMask_cols;
            }
            else{
                ja2 = j;
            }

            i = ic + d_common.mask_conv_ioffset;
            ip1 = i + 1;

            if(d_common.mask_rows < ip1){
                ia1 = ip1 - d_common.mask_rows;
            }
            else{
                ia1 = 1;
            }
            if(d_common.tMask_rows < i){
                ia2 = d_common.tMask_rows;
            }
            else{
                ia2 = i;
            }

            s = 0;

            for(ja=ja1; ja2 >= ja; ja++){
                jb = jp1 - ja;
                for(ia=ia1; ia2 >= ia; ia++){
                    ib = ip1 - ia;
                    s = s + d_unique_ptr[bx].d_tMask[d_common.tMask_rows*(ja-1)+ia-1] * 1;
                }
            }

            d_unique_ptr[bx].d_mask_conv[ei_new] = d_unique_ptr[bx].d_in2_sqr_sub2[ei_new] * s;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        ei_new = tx;
        while(ei_new < d_common.mask_conv_rows){
            for(i=0; i<d_common.mask_conv_cols; i++){
                largest_coordinate_current = ei_new*d_common.mask_conv_rows+i;
                largest_value_current = fabs(d_unique_ptr[bx].d_mask_conv[largest_coordinate_current]);
                if(largest_value < largest_value_current){
                    largest_coordinate = largest_coordinate_current;
                    largest_value = largest_value_current;
                }
            }
            par_max_coo[ei_new] = largest_coordinate;
            par_max_val[ei_new] = largest_value;

            ei_new = ei_new + NUMBER_THREADS;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if(0 == tx){
            for(i = 0; i < d_common.mask_conv_rows; i++){
                if(fin_max_val < par_max_val[i]){
                    fin_max_val = par_max_val[i];
                    fin_max_coo = par_max_coo[i];
                }
            }

            largest_row = (fin_max_coo+1) % d_common.mask_conv_rows - 1;
            largest_col = (fin_max_coo+1) / d_common.mask_conv_rows;
            if((fin_max_coo+1) % d_common.mask_conv_rows == 0){
                largest_row = d_common.mask_conv_rows - 1;
                largest_col -= 1;
            }

            largest_row += 1;
            largest_col += 1;
            offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
            offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
            pointer = d_common_change.frame_no+d_unique_ptr[bx].point_no*d_common.no_frames;
            d_unique_ptr[bx].d_tRowLoc[pointer] = d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] + offset_row;
            d_unique_ptr[bx].d_tColLoc[pointer] = d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] + offset_col;
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if(d_common_change.frame_no != 0 && (d_common_change.frame_no)%10 == 0){
        loc_pointer = d_unique_ptr[bx].point_no*d_common.no_frames+d_common_change.frame_no;
        d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] = d_unique_ptr[bx].d_tRowLoc[loc_pointer];
        d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] = d_unique_ptr[bx].d_tColLoc[loc_pointer];

        ei_new = tx;
        while(ei_new < d_common.in_elem){
            row = (ei_new+1) % d_common.in_rows - 1;
            col = (ei_new+1) / d_common.in_rows + 1 - 1;
            if((ei_new+1) % d_common.in_rows == 0){
                row = d_common.in_rows - 1;
                col -= 1;
            }

            ori_row = d_unique_ptr[bx].d_Row[d_unique_ptr[bx].point_no] - 25 + row - 1;
            ori_col = d_unique_ptr[bx].d_Col[d_unique_ptr[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col*d_common.frame_rows+ori_row;

            d_in[ei_new] = d_common.alpha*d_in[ei_new] + (1.00-d_common.alpha)*d_common_change.d_frame[ori_pointer];

            ei_new = ei_new + NUMBER_THREADS;
        }
    }
}

