mergeSortPass(float4 *result, int nrElems, int threadsPerDiv, const float4 *texData) 
{
	int tid = (blockIdx.x * blockDim.x) + threadIdx.x; 

	int division = tid / threadsPerDiv; 
	if(division >= DIVISIONS) return; 

	int int_tid = tid - division * threadsPerDiv; 
	int Astart = constStartAddr[division] + int_tid * nrElems; 

	int Bstart = Astart + nrElems/2;
	float4 *resStart = &(result[Astart]); 

	if(Astart >= constStartAddr[division + 1]) 
		return; 
	if(Bstart >= constStartAddr[division + 1]){
		for(int i=0; i<(constStartAddr[division + 1] - Astart); i++)
		{
			resStart[i] = texData[Astart + i]; 
		}
		return; 
	}

	int aidx = 0; 
	int bidx = 0; 
	int outidx = 0; 
	float4 a, b;
	a = texData[Astart + aidx];  
	b = texData[Bstart + bidx]; 

	while(true)
	{
		float4 nextA = texData[Astart + aidx + 1]; 
		float4 nextB = texData[Bstart + bidx + 1]; 

		float4 na = getLowest(a,b); 
		float4 nb = getHighest(a,b); 
		a = sortElem(na); 
		b = sortElem(nb); 

		resStart[outidx++] = a; 

		bool elemsLeftInA; 
		bool elemsLeftInB;

		elemsLeftInA = (aidx + 1 < nrElems/2); 
		elemsLeftInB = (bidx + 1 < nrElems/2) && (Bstart + bidx + 1 < constStartAddr[division + 1]); 

		if(elemsLeftInA){
			if(elemsLeftInB){
				if(nextA.x < nextB.x) { aidx += 1; a = nextA; }  
				else { bidx += 1;  a = nextB; }
			}
			else {
				aidx += 1; a = nextA;
			}
		}
		else {
			if(elemsLeftInB){
				bidx += 1;  a = nextB;
			}
			else {
				break; 
			}
		}

	}
	resStart[outidx++] = b;
}

