static float4 getLowest(float4 a, float4 b)
{

	a.x = (b.w > a.x) ? a.x : b.w; 
	a.y = (b.z > a.y) ? a.y : b.z; 
	a.z = (b.y > a.z) ? a.z : b.y; 
	a.w = (b.x > a.w) ? a.w : b.x; 
	return a; 
}

static float4 getHighest(float4 a, float4 b)
{
	b.x = (b.x <= a.w) ? a.w : b.x; 
	b.y = (b.y <= a.z) ? a.z : b.y; 
	b.z = (b.z <= a.y) ? a.y : b.z; 
	b.w = (b.w <= a.x) ? a.x : b.w; 
	return b; 
}

__kernel void
mergeSortFirst(float4 *result, int listsize, float *texData) 
{
    int bx = blockIdx.x;

		if(bx*blockDim.x + threadIdx.x < listsize/4){
			float4 r = texData[bx*blockDim.x + threadIdx.x];
			result[bx * blockDim.x + threadIdx.x] = sortElem(r); 
		}
}

__kernel void
mergeSortPass(float4 *result, int nrElems, int threadsPerDiv, float *texData, int *constStartAddr) 
{
	int tid = (blockIdx.x * blockDim.x) + threadIdx.x; 

	int division = tid / threadsPerDiv; 
	if(division >= DIVISIONS) return; 

	int int_tid = tid - division * threadsPerDiv; 
	int Astart = constStartAddr[division] + int_tid * nrElems; 

	int Bstart = Astart + nrElems/2;
	float4 *resStart = &(result[Astart]); 

	if(constStartAddr[division + 1] <= Astart) 
		return; 
	if(constStartAddr[division + 1] <= Bstart){
		for(int i=0; (constStartAddr[division + 1] - Astart) > i; i++)
		{
			resStart[i] = texData[Astart + i]; 
		}
		return; 
	}

	int aidx = 0; 
	int bidx = 0; 
	int outidx = 0; 
	float4 a, b;
	a = texData[Astart + aidx];  
	b = texData[Bstart + bidx]; 

	while(true)
	{

		float4 nextA = texData[Astart + aidx + 1]; 
		float4 nextB = texData[Bstart + bidx + 1]; 

		float4 na = getLowest(a,b); 
		float4 nb = getHighest(a,b); 
		a = sortElem(na); 
		b = sortElem(nb); 

		resStart[outidx++] = a; 

		bool elemsLeftInA; 
		bool elemsLeftInB;

		elemsLeftInA = (nrElems/2 > aidx + 1); 
		elemsLeftInB = (nrElems/2 > bidx + 1) && (constStartAddr[division + 1] > Bstart + bidx + 1); 

		if(elemsLeftInA){
			if(elemsLeftInB){
				if(nextB.x > nextA.x) { aidx = aidx + (1); a = nextA; }  
				else { bidx = bidx + (1);  a = nextB; }
			}
			else {
				aidx = aidx + (1); a = nextA;
			}
		}
		else {
			if(elemsLeftInB){
				bidx = bidx + (1);  a = nextB;
			}
			else {
				break; 
			}
		}

	}
	resStart[outidx++] = b;
}

__kernel void
mergepack(float *orig, float *result, int *finalStartAddr, int *constStartAddr, int *nullElems) 
{
	int idx = (blockIdx.x * blockDim.x) + threadIdx.x; 
	int division = blockIdx.y; 

	if(finalStartAddr[division + 1] <= (finalStartAddr[division] + idx)) return; 
	result[finalStartAddr[division] + idx] = orig[constStartAddr[division]*4 + nullElems[division] + idx]; 
