	fp kcanCaon;																	
	fp kcanCaM4on;																	
	fp kcanCaM4off;																	
	fp kcanCaM2on;
	fp kcanCaM2off;
	fp kcanCaM0on;
	fp kcanCaM0off;
	fp k02can;
	fp k20can;
	fp k24can;
