	fp dCa2CaM;
	fp dCa4CaM;
	fp dCaMB;
	fp dCa2CaMB;
	fp dCa4CaMB;


	fp dPb2;																					
	fp dPb;																					
	fp dPt;																					
	fp dPt2;																					
	fp dPa;																					


