	fp kcanCaoff;																	
	fp kcanCaon;																	
	fp kcanCaM4on;																	
	fp kcanCaM4off;																	
	fp kcanCaM2on;
	fp kcanCaM2off;
	fp kcanCaM0on;
	fp kcanCaM0off;
	fp k02can;
	fp k20can;
	fp k24can;
	fp k42can;


	fp rcn02;
	fp rcn24;


	fp B;
	fp rcn02B;
	fp rcn24B;
	fp rcn0B;
	fp rcn2B;
	fp rcn4B;


	fp Ca2CaN;
	fp rcnCa4CaN;
