	fp dCa2CaMB;
	fp dCa4CaMB;


	fp dPb2;																					
	fp dPb;																					
	fp dPt;																					
	fp dPt2;																					
	fp dPa;																					


	fp dCa4CaN;																			
	fp dCaMCa4CaN;																	
	fp dCa2CaMCa4CaN;																
	fp dCa4CaMCa4CaN;																







	Btot = d_params[params_offset+1];
	CaMKIItot = d_params[params_offset+2];
	CaNtot = d_params[params_offset+3];
	PP1tot = d_params[params_offset+4];
