void read_impl(	char* filename,
					fp* input,
					int data_rows, 
					int data_cols,
					int major){





	FILE* fid;
	int i, j;
	fp temp;





	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf( "The file was not opened for reading\n" );
		return;
	}





	if(major==0){																
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%f", &temp);
				input[i*data_cols+j] = (fp)temp;
			}
		}
	}
	else{																				
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%f", &temp);
				input[j*data_rows+i] = (fp)temp;
			}
		}
	}





	fclose(fid);

}

long long get_time_impl() {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000) + tv.tv_usec;
}

int main_impl(int argc, char *argv []){









	int xmax;
	int workload;
	int mode;









	if(4 != argc){
		printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 3\n", argc-1);
		return 0;
	}





	else{





		xmax = atoi(argv[1]);
		if(0 > xmax){
			printf("ERROR: %d is the incorrect end of simulation interval, use numbers > 0\n", xmax);
			return 0;
		}





		workload = atoi(argv[2]);
		if(workload<0){
			printf("ERROR: %d is the incorrect number of instances of simulation, use numbers > 0\n", workload);
			return 0;
		}





		mode = 0;
		mode = atoi(argv[3]);
		if(0 != mode && mode != 1){
			printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode);
			return 0;
		}

	}





	if(mode == 0){

		work_impl(	xmax,
					workload);

	}





	else{

		work_2_impl(	xmax,
						workload);

	}





	return 0;

}

