					cl_mem d_initvalu,
					cl_mem d_finavalu,
					cl_mem d_params,
					cl_mem d_com,
					cl_command_queue command_queue,
					cl_kernel kernel,
					long long *timecopyin,
					long long *timecopykernel,
					long long *timecopyout) {

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmin > xmax || 0.0 >= h){
		return -2;
	}

	if (xmin == xmax){
		return 0; 
	}

	if ((xmax - xmin) < h ) { 
		h = (fp)xmax - (fp)xmin; 
	}

	for(k=1; xmax >= k; k++) {

		x[k] = k-1;
		h = h_init;

		scale_fina = 1.0;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8_impl(	x[k],
										h,
										y[k-1],
										y[k],
										err,
										params,
										com,
										d_initvalu,
										d_finavalu,
										d_params,
										d_com,
										command_queue,
										kernel,
										timecopyin,
										timecopykernel,
										timecopyout);

			for(i=0; i<EQUATIONS; i++){
				if(0 < err[i]){
					error = 1;
				}
			}
			if (1 != error) {
				scale_fina = MAX_SCALE_FACTOR; 
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(0.0 == y[k-1][i]){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale_min > scale[i]){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( ( tolerance * yy[i] ) < err[i] ){
					outside = 1;
				}
			}
			if (0 == outside){
				break;
			}

			h = h * scale_fina;

			if (0.9 <= h) {
				h = 0.9;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}

			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}

		}

		x[k] = x[k] + h;

		if ( ATTEMPTS <= j ) {
			return -1; 
		}

	}

	free(err);
	free(scale);
	free(yy);

	return 0;
}

