	x_mem = workload * (xmax+1) * sizeof(fp);
	x= (fp *) malloc(x_mem);
	err = clEnqueueWriteBuffer(command_queue, d_x, 1, 0, x_mem, x, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	params_mem = workload * PARAMETERS * sizeof(fp);
	params= (fp *) malloc(params_mem);
	err = clEnqueueWriteBuffer(command_queue, d_params, 1, 0, params_mem, params, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	com_mem = workload * 3 * sizeof(fp);
	err = clEnqueueWriteBuffer(command_queue, d_com, 1, 0, com_mem, NULL, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	err_mem = workload * EQUATIONS * sizeof(fp);
	err = clEnqueueWriteBuffer(command_queue, d_err, 1, 0, err_mem, NULL, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	scale_mem = workload * EQUATIONS * sizeof(fp);
	err = clEnqueueWriteBuffer(command_queue, d_scale, 1, 0, scale_mem, NULL, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	yy_mem = workload * EQUATIONS * sizeof(fp);
	err = clEnqueueWriteBuffer(command_queue, d_yy, 1, 0, yy_mem, NULL, 0, NULL, NULL);
