	if (err != CL_SUCCESS) return 0;

	finavalu_temp_mem = workload * 13* EQUATIONS * sizeof(fp);
	err = clEnqueueWriteBuffer(command_queue, d_finavalu_temp, 1, 0, finavalu_temp_mem, NULL, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	time2 = get_time();

	for(i=0; workload > i; i++){
		pointer = i * (xmax+1) + 0;
		x[pointer] = 0;
	}
	err = clEnqueueWriteBuffer(command_queue, d_x, 1, 0, x_mem, x, 0, NULL, NULL);
	if (err != CL_SUCCESS) return 0;

	for(i=0; workload > i; i++){
