	else{
		blocks_x = workload/NUMBER_THREADS;
		if (0 != workload % NUMBER_THREADS){
			blocks_x += 1;
		}
	}

	size_t local_work_size[1];
	local_work_size[0] = NUMBER_THREADS;
	size_t global_work_size[1];
	global_work_size[0] = blocks_x * NUMBER_THREADS;

