	free(params);
	clReleaseMemObject(d_params);

	clReleaseMemObject(d_com);
	clReleaseMemObject(d_err);
	clReleaseMemObject(d_scale);
	clReleaseMemObject(d_yy);
	clReleaseMemObject(d_initvalu_temp);
	clReleaseMemObject(d_finavalu_temp);

	time6= get_time();

	printf("Time spent in different stages of the application:\n");
