__global__ void reduce_kernel(long d_Ne, long d_no, int d_mul, fp *d_sums, fp *d_sums2, int blocks2_work_size) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;
    int nf = NUMBER_THREADS - (gridDim.x * NUMBER_THREADS - d_no);
    int df = 0;

    __shared__ fp d_psum[NUMBER_THREADS];
    __shared__ fp d_psum2[NUMBER_THREADS];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    }

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (gridDim.x - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

__global__ void srad_kernel(fp lambda, int Nr, int Nc, long Ne, 
                            const int *d_iN, const int *d_iS, const int *d_jE, const int *d_jW,
                            fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE, fp q0sqr, fp *d_c, fp *d_I) {

    int idx = blockIdx.x * NUMBER_THREADS + threadIdx.x;

    if (idx < Ne) {
        int i = idx / Nc;
        int j = idx % Nc;

        fp Jc = d_I[idx];

        int iN_idx = d_iN[i];
        int iS_idx = d_iS[i];
        int jW_idx = d_jW[j];
        int jE_idx = d_jE[j];

        fp dN_val = d_I[iN_idx * Nc + j] - Jc;
        fp dS_val = d_I[iS_idx * Nc + j] - Jc;
        fp dW_val = d_I[i * Nc + jW_idx] - Jc;
        fp dE_val = d_I[i * Nc + jE_idx] - Jc;

        d_dN[idx] = dN_val;
        d_dS[idx] = dS_val;
        d_dW[idx] = dW_val;
        d_dE[idx] = dE_val;

        fp G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
        fp L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        fp num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        d_c[idx] = c_val;
    }
}

__global__ void srad2_kernel(fp lambda, int Nr, int Nc, long Ne,
                             const int *d_iN, const int *d_iS, const int *d_jE, const int *d_jW,
                             const fp *d_dN, const fp *d_dS, const fp *d_dW, const fp *d_dE,
                             const fp *d_c, fp *d_I) {

    int idx = blockIdx.x * NUMBER_THREADS + threadIdx.x;

    if (idx < Ne) {
        int i = idx / Nc;
        int j = idx % Nc;

        int iS_idx = d_iS[i];
        int jE_idx = d_jE[j];

        fp cN = d_c[idx];
        fp cS = d_c[iS_idx * Nc + j];
        fp cW = d_c[idx];
        fp cE = d_c[i * Nc + jE_idx];

        fp D = cN * d_dN[idx] + cS * d_dS[idx] + cW * d_dW[idx] + cE * d_dE[idx];

        d_I[idx] = d_I[idx] + 0.25f * lambda * D;
    }
}

__global__ void compress_kernel(long d_Ne, fp *d_I) {
    int bx = blockIdx.x;
