// OpenCL kernels for SRAD algorithm
// Compatible with 1D execution model of the provided wrapper.

// Kernel 1: Computes coefficients (C) and differences (N, S, E, W)
__attribute__((kernel)) void srad_kernel(
          write_only float *E_C, 
          write_only float *W_C, 
          write_only float *N_C, 
          write_only float *S_C,
          const float * J_cuda, 
          write_only float * C_cuda, 
          int cols, 
          int rows, 
          float q0sqr) 
{
  int idx = get_global_id(0);
  int total = cols * rows;

  if (idx >= total) return;

  int j = idx % cols;
  int i = idx / cols;

  float jc = J_cuda[idx];

  // Determine neighbor indices with boundary checks
  int idx_n = (i == 0) ? idx : idx - cols;
  int idx_s = (i == rows - 1) ? idx : idx + cols;
  int idx_w = (j == 0) ? idx : idx - 1;
  int idx_e = (j == cols - 1) ? idx : idx + 1;

  float n_val = J_cuda[idx_n];
  float s_val = J_cuda[idx_s];
  float w_val = J_cuda[idx_w];
  float e_val = J_cuda[idx_e];

  float dN = n_val - jc;
  float dS = s_val - jc;
  float dW = w_val - jc;
  float dE = e_val - jc;

  float g2 = 0.0f;
  float l = 0.0f;

  if (jc != 0.0f) {
      g2 = (dN*dN + dS*dS + dW*dW + dE*dE) / (jc * jc);
      l = (dN + dS + dW + dE) / jc;
  }

  float num = (0.5f * g2) - ((1.0f/16.0f) * (l*l));
  float den = 1.0f + (0.25f * l);

  float qsqr = 0.0f;
  if (den != 0.0f) {
      qsqr = num / (den * den);
  }

  float den2 = q0sqr * (1.0f + q0sqr);
  float c = 1.0f;

  if (den2 != 0.0f) {
      float diff = qsqr - q0sqr;
      float ratio = diff / den2;
      c = 1.0f / (1.0f + ratio);
  }

  if (c < 0.0f) c = 0.0f;
  else if (c > 1.0f) c = 1.0f;

  C_cuda[idx] = c;
  E_C[idx] = dE;
  W_C[idx] = dW;
  S_C[idx] = dS;
  N_C[idx] = dN;
}

// Kernel 2: Updates the image J using the computed coefficients and differences
__attribute__((kernel)) void srad2_kernel(
          const float *E_C, 
          const float *W_C, 
          const float *N_C, 
          const float *S_C,	
          float * J_cuda, 
          const float * C_cuda, 
          int cols, 
          int rows, 
          float lambda,
          float q0sqr) 
{
  int idx = get_global_id(0);
  int total = cols * rows;

  if (idx >= total) return;

  int j = idx % cols;
  int i = idx / cols;

  // Neighbor indices
  int idx_n = (i == 0) ? idx : idx - cols;
  int idx_s = (i == rows - 1) ? idx : idx + cols;
  int idx_w = (j == 0) ? idx : idx - 1;
  int idx_e = (j == cols - 1) ? idx : idx + 1;

  float cc = C_cuda[idx];

  // Preserve the specific asymmetry from the original CPU/GPU code:
  // cN = current, cS = south neighbor, cW = current, cE = east neighbor
  float cN = cc;
  float cS = C_cuda[idx_s];
  float cW = cc;
  float cE = C_cuda[idx_e];

  float d_sum = cN * N_C[idx] + cS * S_C[idx] + cW * W_C[idx] + cE * E_C[idx];

  J_cuda[idx] = J_cuda[idx] + 0.25f * lambda * d_sum;
}

