// Reduction kernel adapted for OpenCL 1D execution with local memory
__attribute__((kernel)) void reduce_kernel(long d_Ne, int d_no, int d_mul, float *d_sums, float *d_sums2) {
    int idx = get_global_id(0);
    int tid = get_local_id(0);
    int gid = get_group_id(0);

    // Use dynamic local array size based on BLOCK_SIZE or a safe max
    float local_sums[BLOCK_SIZE];
    float local_sums2[BLOCK_SIZE];

    // Load data
    if (idx < d_no) {
        local_sums[tid] = d_sums[idx * d_mul];
        local_sums2[tid] = d_sums2[idx * d_mul];
    } else {
        local_sums[tid] = 0.0f;
        local_sums2[tid] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Tree reduction
    for (int stride = get_local_size(0) / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            local_sums[tid] += local_sums[tid + stride];
            local_sums2[tid] += local_sums2[tid + stride];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write result
    if (tid == 0) {
        int out_idx = gid * d_mul * get_local_size(0);
        // Ensure we don't write out of bounds if the logic drifts
        if (out_idx < d_Ne || gid == 0) { 
             d_sums[out_idx] = local_sums[0];
             d_sums2[out_idx] = local_sums2[0];
        }
    }
}

